  1→import {
  2→  Loader2,
  3→  Download,
  4→  Share2,
  5→  Check,
  6→  BarChart3,
  7→  Bot,
  8→  Clock,
  9→  MessageSquare,
 10→  Wrench,
 11→  FolderOpen,
 12→  Cpu,
 13→  Calendar,
 14→  Hash,
 15→  Layers,
 16→  Zap,
 17→  GitBranch,
 18→  List,
 19→} from "lucide-react";
 20→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
 21→import { useAppContext } from "../../app";
 22→import type { Step, Trajectory, FlowData } from "../../types";
 23→import { StepBlock } from "./message-block";
 24→import { SubAgentBlock } from "./sub-agent-block";
 25→import { StepTimeline } from "./step-timeline";
 26→import { PromptNavPanel } from "./prompt-nav-panel";
 27→import { FlowDiagram } from "./flow-diagram";
 28→import { computeFlow, type FlowPhaseGroup } from "./flow-layout";
 29→import { formatTokens, formatDuration, formatCost, extractUserText, baseProjectName } from "../../utils";
 30→import { TOGGLE_ACTIVE, TOGGLE_INACTIVE, METRIC_LABEL } from "../../styles";
 31→
 32→interface SessionViewProps {
 33→  sessionId: string;
 34→  sharedTrajectories?: Trajectory[];
 35→  shareToken?: string;
 36→}
 37→
 38→export function SessionView({ sessionId, sharedTrajectories, shareToken }: SessionViewProps) {
 39→  const { fetchWithToken } = useAppContext();
 40→  const [trajectories, setTrajectories] = useState<Trajectory[]>([]);
 41→  const [loading, setLoading] = useState(true);
 42→  const [error, setError] = useState("");
 43→  const [activeStepId, setActiveStepId] = useState<string | null>(null);
 44→  const [promptNavWidth, setPromptNavWidth] = useState(224);
 45→  const [sessionCost, setSessionCost] = useState<number | null>(null);
 46→  const [shareStatus, setShareStatus] = useState<"idle" | "sharing" | "copied">("idle");
 47→  const [viewMode, setViewMode] = useState<"timeline" | "flow">("timeline");
 48→  const [flowData, setFlowData] = useState<FlowData | null>(null);
 49→  const [flowLoading, setFlowLoading] = useState(false);
 50→  const stepsRef = useRef<HTMLDivElement>(null);
 51→  const isNavigatingRef = useRef(false);
 52→  const isSharedView = !!sharedTrajectories;
 53→
 54→  const MIN_PROMPT_NAV_WIDTH = 160;
 55→  const MAX_PROMPT_NAV_WIDTH = 400;
 56→
 57→  const handlePromptNavResize = useCallback((delta: number) => {
 58→    setPromptNavWidth((w) =>
 59→      Math.min(MAX_PROMPT_NAV_WIDTH, Math.max(MIN_PROMPT_NAV_WIDTH, w + delta))
 60→    );
 61→  }, []);
 62→
 63→  useEffect(() => {
 64→    setActiveStepId(null);
 65→    setSessionCost(null);
 66→    setFlowData(null);
 67→    setViewMode("timeline");
 68→
 69→    // When rendering shared data, skip the API fetch
 70→    if (sharedTrajectories) {
 71→      setTrajectories(sharedTrajectories);
 72→      setLoading(false);
 73→      return;
 74→    }
 75→
 76→    setLoading(true);
 77→    setError("");
 78→    setTrajectories([]);
 79→
 80→    fetchWithToken(`/api/sessions/${sessionId}`)
 81→      .then((res) => {
 82→        if (!res.ok) throw new Error(`Failed to load session: ${res.status}`);
 83→        return res.json();
 84→      })
 85→      .then((data: Trajectory[]) => {
 86→        setTrajectories(data);
 87→      })
 88→      .catch((err: Error) => setError(err.message))
 89→      .finally(() => setLoading(false));
 90→  }, [sessionId, fetchWithToken, sharedTrajectories]);
 91→
 92→  // Fetch session analytics for cost estimation (non-blocking, skip for shared views)
 93→  useEffect(() => {
 94→    if (!sessionId || loading || isSharedView) return;
 95→    fetchWithToken(`/api/analysis/sessions/${sessionId}/stats`)
 96→      .then((res) => (res.ok ? res.json() : null))
 97→      .then((data) => {
 98→        if (data?.cost_usd != null) setSessionCost(data.cost_usd);
 99→      })
100→      .catch(() => {});
101→  }, [sessionId, loading, fetchWithToken]);
102→
103→  // Fetch flow data lazily when user toggles to flow view
104→  useEffect(() => {
105→    if (viewMode !== "flow" || flowData || flowLoading || !sessionId) return;
106→    setFlowLoading(true);
107→    const url = isSharedView && shareToken
108→      ? `/api/shares/${shareToken}/flow`
109→      : `/api/sessions/${sessionId}/flow`;
110→    fetchWithToken(url)
111→      .then((res) => (res.ok ? res.json() : null))
112→      .then((data: FlowData | null) => {
113→        if (data) setFlowData(data);
114→      })
115→      .catch(() => {})
116→      .finally(() => setFlowLoading(false));
117→  }, [viewMode, flowData, flowLoading, sessionId, fetchWithToken, isSharedView, shareToken]);
118→
119→  const main = useMemo(
120→    () => trajectories.find((t) => !t.parent_trajectory_ref) ?? trajectories[0] ?? null,
121→    [trajectories]
122→  );
123→
124→  const subAgents = useMemo(
125→    () =>
126→      trajectories
127→        .filter((t) => !!t.parent_trajectory_ref)
128→        .sort((a, b) => {
129→          const ta = a.timestamp ? new Date(a.timestamp).getTime() : 0;
130→          const tb = b.timestamp ? new Date(b.timestamp).getTime() : 0;
131→          return ta - tb;
132→        }),
133→    [trajectories]
134→  );
135→
136→  // Build a map: step_id -> sub-agent trajectories spawned from that step.
137→  // Phase 1 links via observation.subagent_trajectory_ref (explicit linkage).
138→  // Phase 2 places unlinked sub-agents (e.g. compaction) at the
139→  // chronologically correct position using timestamp heuristics.
140→  const subAgentsByStep = useMemo(() => {
141→    const map = new Map<string, Trajectory[]>();
142→    const orphans: Trajectory[] = [];
143→    const unlinked: Trajectory[] = [];
144→
145→    for (const sub of subAgents) {
146→      let placed = false;
147→      if (main?.steps) {
148→        for (const step of main.steps) {
149→          if (!step.observation) continue;
150→          for (const result of step.observation.results) {
151→            if (!result.subagent_trajectory_ref) continue;
152→            for (const ref of result.subagent_trajectory_ref) {
153→              if (ref.session_id === sub.session_id) {
154→                const existing = map.get(step.step_id) || [];
155→                existing.push(sub);
156→                map.set(step.step_id, existing);
157→                placed = true;
158→                break;
159→              }
160→            }
161→            if (placed) break;
162→          }
163→          if (placed) break;
164→        }
165→      }
166→      if (!placed) unlinked.push(sub);
167→    }
168→
169→    // Place unlinked sub-agents at the last main step whose timestamp
170→    // is <= the sub-agent's start timestamp. Falls back to orphans
171→    // only when no timestamp is available.
172→    for (const sub of unlinked) {
173→      const subTs = sub.timestamp ? new Date(sub.timestamp).getTime() : NaN;
174→      if (!isNaN(subTs) && main?.steps) {
175→        let bestStepId: string | null = null;
176→        for (const step of main.steps) {
177→          if (!step.timestamp) continue;
178→          const stepTs = new Date(step.timestamp).getTime();
179→          if (stepTs <= subTs) bestStepId = step.step_id;
180→          else break;
181→        }
182→        if (bestStepId) {
183→          const existing = map.get(bestStepId) || [];
184→          existing.push(sub);
185→          map.set(bestStepId, existing);
186→          continue;
187→        }
188→      }
189→      orphans.push(sub);
190→    }
191→
192→    return { map, orphans };
193→  }, [main, subAgents]);
194→
195→  const steps = (main?.steps || []) as Step[];
196→
197→  const userStepIds = useMemo(() => {
198→    return steps
199→      .filter((s) => s.source === "user" && extractUserText(s))
200→      .map((s) => s.step_id);
201→  }, [steps]);
202→
203→  // Compute flow phases for the nav panel when in flow mode
204→  const flowPhases: FlowPhaseGroup[] | undefined = useMemo(() => {
205→    if (!flowData || viewMode !== "flow") return undefined;
206→    const result = computeFlow(steps, flowData.tool_graph, flowData.phase_segments);
207→    return result.phases;
208→  }, [flowData, viewMode, steps]);
209→
210→  const [activePhaseIdx, setActivePhaseIdx] = useState<number | null>(null);
211→
212→  const SCROLL_SUPPRESS_MS = 800;
213→
214→  const handlePhaseNavigate = useCallback((phaseIdx: number) => {
215→    const el = document.getElementById(`flow-phase-${phaseIdx}`);
216→    if (!el) return;
217→    setActivePhaseIdx(phaseIdx);
218→    el.scrollIntoView({ behavior: "smooth", block: "start" });
219→  }, []);
220→
221→  // IntersectionObserver to track which user prompt is currently visible
222→  useEffect(() => {
223→    if (!stepsRef.current || userStepIds.length < 2) return;
224→
225→    const observer = new IntersectionObserver(
226→      (entries) => {
227→        if (isNavigatingRef.current) return;
228→        let topEntry: IntersectionObserverEntry | null = null;
229→        for (const entry of entries) {
230→          if (!entry.isIntersecting) continue;
231→          if (!topEntry || entry.boundingClientRect.top < topEntry.boundingClientRect.top) {
232→            topEntry = entry;
233→          }
234→        }
235→        if (topEntry) {
236→          setActiveStepId(topEntry.target.id.replace("step-", ""));
237→        }
238→      },
239→      {
240→        root: stepsRef.current,
241→        rootMargin: "-10% 0px -80% 0px",
242→        threshold: 0,
243→      }
244→    );
245→
246→    for (const stepId of userStepIds) {
247→      const el = document.getElementById(`step-${stepId}`);
248→      if (el) observer.observe(el);
249→    }
250→
251→    return () => observer.disconnect();
252→  }, [userStepIds]);
253→
254→  const handlePromptNavigate = useCallback((stepId: string) => {
255→    const el = document.getElementById(`step-${stepId}`);
256→    if (!el) return;
257→    isNavigatingRef.current = true;
258→    setActiveStepId(stepId);
259→    el.scrollIntoView({ behavior: "smooth", block: "start" });
260→    setTimeout(() => {
261→      isNavigatingRef.current = false;
262→    }, SCROLL_SUPPRESS_MS);
263→  }, []);
264→
265→  if (loading) {
266→    return (
267→      <div className="flex items-center justify-center h-full">
268→        <div className="flex flex-col items-center gap-5">
269→          <div className="relative flex items-center justify-center">
270→            {/* Ambient glow */}
271→            <div className="absolute w-24 h-24 bg-cyan-500/10 rounded-full blur-2xl animate-pulse" />
272→            {/* Track ring */}
273→            <div className="w-16 h-16 rounded-full border-[3px] border-zinc-800" />
274→            {/* Spinning arc */}
275→            <div className="absolute w-16 h-16 rounded-full border-[3px] border-transparent border-t-cyan-400 animate-spin" />
276→          </div>
277→          <div className="text-center space-y-1">
278→            <p className="text-base font-medium text-zinc-200">Loading session</p>
279→            <p className="text-xs text-zinc-500">Parsing trajectory data…</p>
280→          </div>
281→        </div>
282→      </div>
283→    );
284→  }
285→
286→  if (error) {
287→    return (
288→      <div className="flex items-center justify-center h-full p-4">
289→        <div className="text-center bg-rose-900/20 border border-rose-800 rounded-lg p-6 max-w-md">
290→          <p className="text-sm font-semibold text-rose-300 mb-2">Failed to load session</p>
291→          <p className="text-xs text-rose-400 mb-4 font-mono break-all">{error}</p>
292→          <button
293→            onClick={() => window.location.reload()}
294→            className="px-3 py-1 bg-rose-700/50 hover:bg-rose-700 rounded text-xs text-rose-200 transition"
295→          >
296→            Retry
297→          </button>
298→        </div>
299→      </div>
300→    );
301→  }
302→
303→  const handleShare = async () => {
304→    setShareStatus("sharing");
305→    try {
306→      const res = await fetchWithToken("/api/shares", {
307→        method: "POST",
308→        headers: { "Content-Type": "application/json" },
309→        body: JSON.stringify({ session_id: sessionId }),
310→      });
311→      if (!res.ok) throw new Error(`Failed to create share: ${res.status}`);
312→      const data = await res.json();
313→      await navigator.clipboard.writeText(data.url);
314→      setShareStatus("copied");
315→      setTimeout(() => setShareStatus("idle"), 2000);
316→    } catch (err) {
317→      console.error("Share failed:", err);
318→      setShareStatus("idle");
319→    }
320→  };
321→
322→  if (!main) return null;
323→
324→  const metrics = main.final_metrics;
325→  const promptCount = steps.filter(
326→    (s) => s.source === "user" && !s.extra?.is_skill_output && extractUserText(s)
327→  ).length;
328→  const skillCount = steps.filter(
329→    (s) => s.source === "user" && s.extra?.is_skill_output
330→  ).length;
331→  const totalTokens =
332→    (metrics?.total_prompt_tokens || 0) +
333→    (metrics?.total_completion_tokens || 0);
334→
335→  const isVisibleStep = (s: Step): boolean => {
336→    if (s.source === "user") {
337→      if (typeof s.message === "string") return !!s.message.trim();
338→      return s.message.length > 0;
339→    }
340→    return s.source === "agent" || s.source === "system";
341→  };
342→
343→  return (
344→    <div className="h-full flex flex-col overflow-hidden">
345→      {/* Session Header */}
346→      <div className="shrink-0 bg-zinc-900/95 border-b border-zinc-800 px-6 py-4">
347→        <div className="max-w-7xl mx-auto">
348→          {/* Row 1: Title + Meta Pills */}
349→          <div className="flex items-start justify-between mb-3">
350→            <div className="min-w-0 flex-1">
351→              <div className="flex items-center gap-2">
352→                <MetaPill
353→                  icon={<Hash className="w-3 h-3" />}
354→                  label={main.session_id.slice(0, 8)}
355→                  color="text-zinc-300"
356→                  tooltip={`Session ID: ${main.session_id}`}
357→                />
358→                <h2 className="text-sm font-semibold text-zinc-100 truncate">
359→                  {main.first_message || "Session"}
360→                </h2>
361→              </div>
362→              <div className="flex flex-wrap items-center gap-1.5 mt-2">
363→                {main.agent.model_name && (
364→                  <MetaPill
365→                    icon={<Cpu className="w-3 h-3" />}
366→                    label={`${main.agent.name}@${main.agent.model_name}`}
367→                    color="text-amber-300"
368→                    tooltip="Agent model used for this session"
369→                  />
370→                )}
371→                {main.timestamp && (
372→                  <MetaPill
373→                    icon={<Calendar className="w-3 h-3" />}
374→                    label={formatCreatedTime(main.timestamp)}
375→                    color="text-zinc-200"
376→                    tooltip="Session start time"
377→                  />
378→                )}
379→                {metrics && (
380→                  <MetaPill
381→                    icon={<Clock className="w-3 h-3" />}
382→                    label={formatDuration(metrics.duration)}
383→                    color="text-cyan-400"
384→                    tooltip="Total wall-clock duration of this session"
385→                  />
386→                )}
387→                <MetaPill
388→                  icon={<MessageSquare className="w-3 h-3" />}
389→                  label={`${promptCount} prompt${promptCount !== 1 ? "s" : ""}`}
390→                  color="text-blue-400"
391→                  tooltip="User prompts — messages typed by the human operator"
392→                />
393→                {skillCount > 0 && (
394→                  <MetaPill
395→                    icon={<Zap className="w-3 h-3" />}
396→                    label={`${skillCount} skill${skillCount !== 1 ? "s" : ""}`}
397→                    color="text-amber-300"
398→                    tooltip="Skill invocations — reusable prompts auto-injected by the agent"
399→                  />
400→                )}
401→                {metrics && (
402→                  <>
403→                    <MetaPill
404→                      icon={<Wrench className="w-3 h-3" />}
405→                      label={`${metrics.tool_call_count} tools`}
406→                      color="text-amber-400"
407→                      tooltip="Total tool calls made by the agent (Bash, Read, Edit, etc.)"
408→                    />
409→                    {metrics.total_steps && (
410→                      <MetaPill
411→                        icon={<Layers className="w-3 h-3" />}
412→                        label={`${metrics.total_steps} steps`}
413→                        color="text-zinc-200"
414→                        tooltip="Total conversation steps including user, agent, and system turns"
415→                      />
416→                    )}
417→                  </>
418→                )}
419→                {subAgents.length > 0 && (
420→                  <MetaPill
421→                    icon={<Bot className="w-3 h-3" />}
422→                    label={`${subAgents.length} sub-agent${subAgents.length !== 1 ? "s" : ""}`}
423→                    color="text-violet-400"
424→                    tooltip="Sub-agent tasks spawned during this session"
425→                  />
426→                )}
427→                {main.project_path && (
428→                  <MetaPill
429→                    icon={<FolderOpen className="w-3 h-3" />}
430→                    label={baseProjectName(main.project_path)}
431→                    color="text-zinc-200"
432→                    tooltip={main.project_path}
433→                  />
434→                )}
435→              </div>
436→            </div>
437→            <div className="flex items-center gap-1 shrink-0 ml-3">
438→              {/* View mode toggle */}
439→              <div className="flex rounded-md border border-zinc-700 mr-2">
440→                <button
441→                  onClick={() => setViewMode("timeline")}
442→                  className={`flex items-center gap-1 px-2.5 py-1.5 text-xs rounded-l-md transition ${
443→                    viewMode === "timeline" ? TOGGLE_ACTIVE : TOGGLE_INACTIVE
444→                  }`}
445→                >
446→                  <List className="w-3 h-3" />
447→                  Timeline
448→                </button>
449→                <button
450→                  onClick={() => setViewMode("flow")}
451→                  className={`flex items-center gap-1 px-2.5 py-1.5 text-xs rounded-r-md transition ${
452→                    viewMode === "flow" ? TOGGLE_ACTIVE : TOGGLE_INACTIVE
453→                  }`}
454→                >
455→                  <GitBranch className="w-3 h-3" />
456→                  Flow
457→                </button>
458→              </div>
459→              {!isSharedView && (
460→                <button
461→                  onClick={handleShare}
462→                  disabled={shareStatus === "sharing"}
463→                  className="p-2 text-zinc-400 hover:text-zinc-200 hover:bg-zinc-800 rounded transition text-xs disabled:opacity-50"
464→                  title={shareStatus === "copied" ? "Link copied!" : "Share session"}
465→                >
466→                  {shareStatus === "copied" ? (
467→                    <Check className="w-4 h-4 text-emerald-400" />
468→                  ) : shareStatus === "sharing" ? (
469→                    <Loader2 className="w-4 h-4 animate-spin" />
470→                  ) : (
471→                    <Share2 className="w-4 h-4" />
472→                  )}
473→                </button>
474→              )}
475→              <button
476→                onClick={() => {
477→                  const link = document.createElement("a");
478→                  link.href = `/api/sessions/${sessionId}/export`;
479→                  link.download = `vibelens-${sessionId.slice(0, 8)}.json`;
480→                  document.body.appendChild(link);
481→                  link.click();
482→                  document.body.removeChild(link);
483→                }}
484→                className="p-2 text-zinc-400 hover:text-zinc-200 hover:bg-zinc-800 rounded transition text-xs"
485→                title="Download session"
486→              >
487→                <Download className="w-4 h-4" />
488→              </button>
489→            </div>
490→          </div>
491→
492→          {/* Row 2: Token Stats */}
493→          {metrics && (metrics.total_prompt_tokens != null || metrics.total_completion_tokens != null) && (
494→            <div className={`grid ${sessionCost != null ? "grid-cols-6" : "grid-cols-5"} gap-2 text-xs`}>
495→              <TokenStat label="Input" value={metrics.total_prompt_tokens || 0} color="text-cyan-300" tooltip="Prompt tokens sent to the model" />
496→              <TokenStat label="Output" value={metrics.total_completion_tokens || 0} color="text-cyan-300" tooltip="Completion tokens generated by the model" />
497→              <TokenStat label="Cache Read" value={metrics.total_cache_read || 0} color="text-green-300" tooltip="Tokens served from prompt cache (reduced cost)" />
498→              <TokenStat label="Cache Write" value={metrics.total_cache_write || 0} color="text-violet-300" tooltip="Tokens written to prompt cache for future reuse" />
499→              <TokenStat label="Total" value={totalTokens} color="text-amber-300" tooltip="Total tokens (input + output)" />
500→              {sessionCost != null && (
501→                <CostStat value={sessionCost} />
502→              )}
503→            </div>
504→          )}
505→        </div>
506→      </div>
507→
508→      {/* Two-column body: Steps + Prompt Nav */}
509→      <div className="flex-1 flex min-h-0">
510→        {/* Steps / Flow */}
511→        <div ref={stepsRef} className="flex-1 overflow-y-auto">
512→          {viewMode === "timeline" ? (
513→            <div className="max-w-5xl mx-auto px-4 py-6 space-y-3">
514→              {steps.length === 0 ? (
515→                <div className="text-center text-zinc-500 text-sm py-8">
516→                  <BarChart3 className="w-8 h-8 mx-auto mb-2 opacity-50" />
517→                  <p>No steps to display</p>
518→                </div>
519→              ) : (
520→                <>
521→                  <StepTimeline
522→                    entries={steps
523→                      .filter((step) => {
524→                        const visible = isVisibleStep(step);
525→                        const spawnedSubs = subAgentsByStep.map.get(step.step_id);
526→                        return visible || !!spawnedSubs;
527→                      })
528→                      .map((step) => {
529→                        const visible = isVisibleStep(step);
530→                        const spawnedSubs = subAgentsByStep.map.get(step.step_id);
531→                        return {
532→                          step,
533→                          content: (
534→                            <div id={`step-${step.step_id}`} style={{ scrollMarginTop: "1rem" }}>
535→                              {visible && <StepBlock step={step} />}
536→                              {spawnedSubs?.map((sub) => (
537→                                <div key={sub.session_id} id={`subagent-${sub.session_id}`} className="mt-2">
538→                                  <SubAgentBlock
539→                                    trajectory={sub}
540→                                    allTrajectories={trajectories}
541→                                  />
542→                                </div>
543→                              ))}
544→                            </div>
545→                          ),
546→                        };
547→                      })}
548→                    sessionStartMs={
549→                      main.timestamp
550→                        ? new Date(main.timestamp).getTime()
551→                        : null
552→                    }
553→                    sessionStartTimestamp={main.timestamp}
554→                  />
555→                  {subAgentsByStep.orphans.map((sub) => (
556→                    <div key={sub.session_id} id={`subagent-${sub.session_id}`}>
557→                      <SubAgentBlock
558→                        trajectory={sub}
559→                        allTrajectories={trajectories}
560→                      />
561→                    </div>
562→                  ))}
563→                </>
564→              )}
565→            </div>
566→          ) : flowLoading ? (
567→            <div className="flex items-center justify-center h-full">
568→              <div className="text-center">
569→                <Loader2 className="w-8 h-8 text-cyan-500 animate-spin mx-auto mb-2" />
570→                <p className="text-sm text-zinc-400">Building flow diagram...</p>
571→              </div>
572→            </div>
573→          ) : flowData ? (
574→            <div className="max-w-5xl mx-auto px-4 py-6">
575→              <FlowDiagram steps={steps} flowData={flowData} />
576→            </div>
