130→function AgentStep({ step }: { step: Step }) {
131→  // Build observation results indexed by source_call_id for pairing
132→  const obsMap = new Map<string, ObservationResult>();
133→  if (step.observation) {
134→    for (const r of step.observation.results) {
135→      if (r.source_call_id) {
136→        obsMap.set(r.source_call_id, r);
137→      }
138→    }
139→  }
140→
141→  const orphanResults = step.observation?.results.filter(
142→    (r) => !r.source_call_id || !step.tool_calls.some((tc) => tc.tool_call_id === r.source_call_id)
143→  ) ?? [];
144→
145→  const hasConcurrentCalls = step.tool_calls.length > 1;
146→
147→  return (
148→    <div className="space-y-1">
149→      {step.message && (typeof step.message !== "string" || step.message.trim()) && (
150→        <TextBlock content={step.message} />
