153→      {(step.tool_calls.length > 0 || orphanResults.length > 0) && (
154→        <div className="flex flex-col gap-1 mt-1.5">
155→          {hasConcurrentCalls ? (
156→            <ConcurrentToolsBlock toolCalls={step.tool_calls} obsMap={obsMap} />
157→          ) : (
158→            step.tool_calls.map((tc, i) => {
159→              const result = obsMap.get(tc.tool_call_id);
