161→                <div key={`tc-${i}`}>
162→                  <ToolUseBlock toolCall={tc} />
163→                  {result && <ToolResultBlock result={result} />}
164→                </div>
165→              );
166→            })
167→          )}
168→          {orphanResults.map((r, i) => (
169→            <ToolResultBlock key={`orphan-${i}`} result={r} />
