292→const ERROR_PREFIX = "[ERROR] ";
293→
294→function ToolResultBlock({ result }: { result: ObservationResult }) {
295→  const rawContent = result.content;
296→  if (!rawContent) return null;
297→
298→  // Handle multimodal content (images in tool results)
299→  if (Array.isArray(rawContent)) {
300→    return (
301→      <div className="max-w-[85%] mt-1 bg-zinc-900/60 border border-zinc-800 rounded-lg overflow-hidden p-3">
302→        <ContentRenderer content={rawContent} />
303→      </div>
304→    );
305→  }
306→
307→  const isError = rawContent.startsWith(ERROR_PREFIX);
308→  const content = isError ? rawContent.slice(ERROR_PREFIX.length) : rawContent;
309→  if (!content) return null;
310→
311→  const lineCount = content.split("\n").length;
312→  const isShort = lineCount <= AUTO_EXPAND_LINE_THRESHOLD;
313→  const [open, setOpen] = useState(isShort);
314→
315→  if (isShort) {
316→    return (
317→      <div className="max-w-[85%] mt-1 bg-zinc-900/60 border border-zinc-800 rounded-lg overflow-hidden">
318→        <ToolOutput text={content} isError={isError} />
319→      </div>
320→    );
321→  }
322→
323→  const previewSnippet = content.split("\n")[0].slice(0, 80);
324→
325→  return (
326→    <div className="max-w-[85%]">
327→      <button
328→        onClick={() => setOpen(!open)}
329→        className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-[11px] border transition-colors ${
330→          isError
331→            ? "bg-rose-500/10 hover:bg-rose-500/15 text-rose-300 border-rose-500/20"
332→            : "bg-teal-500/10 hover:bg-teal-500/15 text-teal-300 border-teal-500/20"
333→        }`}
334→      >
335→        {open ? <ChevronDown className="w-3 h-3" /> : <ChevronRight className="w-3 h-3" />}
