 27→export function DashboardView({ cache }: DashboardViewProps) {
 28→  const { fetchWithToken } = useAppContext();
 29→  const [stats, setStats] = useState<DashboardStats | null>(cache?.stats ?? null);
 30→  const [toolUsage, setToolUsage] = useState<ToolUsageStat[]>(cache?.toolUsage ?? []);
 31→  const [loading, setLoading] = useState(!cache);
 32→  const [error, setError] = useState<string | null>(null);
 33→  const [selectedProject, setSelectedProject] = useState<string | null>(null);
 34→  const [exporting, setExporting] = useState<"csv" | "json" | null>(null);
 35→  const [showAllProjects, setShowAllProjects] = useState(false);
 36→  const { tip, show, move, hide } = useTooltip();
 37→
 38→  // Populate from cache when it arrives (background preload)
 39→  useEffect(() => {
 40→    if (cache && !stats) {
 41→      setStats(cache.stats);
 42→      setToolUsage(cache.toolUsage);
 43→      setLoading(false);
 44→    }
 45→  }, [cache, stats]);
 46→
 47→  // Fetch on-demand only when filtering by project
 48→  useEffect(() => {
 49→    if (!selectedProject) return;
 50→
 51→    setLoading(true);
 52→    setError(null);
 53→    const params = new URLSearchParams();
 54→    params.set("project_path", selectedProject);
 55→
 56→    Promise.all([
 57→      fetchWithToken(`/api/analysis/dashboard?${params}`)
 58→        .then((r) => {
 59→          if (!r.ok) throw new Error(`HTTP ${r.status}`);
 60→          return r.json();
 61→        }),
 62→      fetchWithToken(`/api/analysis/tool-usage?${params}`)
 63→        .then((r) => (r.ok ? r.json() : []))
 64→        .catch(() => []),
 65→    ])
 66→      .then(([dashData, toolData]: [DashboardStats, ToolUsageStat[]]) => {
 67→        setStats(dashData);
 68→        setToolUsage(toolData);
 69→      })
 70→      .catch((err) => setError(String(err)))
 71→      .finally(() => setLoading(false));
 72→  }, [fetchWithToken, selectedProject]);
 73→
 74→  // Restore cached global data when clearing the project filter
 75→  const handleClearProject = useCallback(() => {
 76→    setSelectedProject(null);
 77→    if (cache) {
 78→      setStats(cache.stats);
 79→      setToolUsage(cache.toolUsage);
 80→    }
