184→        }
185→        if (bestStepId) {
186→          const existing = map.get(bestStepId) || [];
187→          existing.push(sub);
188→          map.set(bestStepId, existing);
189→          continue;
190→        }
191→      }
192→      orphans.push(sub);
193→    }
