556→                                  />
557→                                </div>
558→                              ))}
559→                            </div>
560→                          ),
561→                        };
562→                      })}
563→                    sessionStartMs={
564→                      main.timestamp
565→                        ? new Date(main.timestamp).getTime()
566→                        : null
567→                    }
568→                    sessionStartTimestamp={main.timestamp}
569→                  />
570→                  {subAgentsByStep.orphans.map((sub) => (
