351→function SessionRow({
352→  session,
353→  selectedId,
354→  checkedIds,
355→  onSelect,
356→  onToggle,
357→  showProject,
358→}: {
359→  session: Trajectory;
360→  selectedId: string | null;
361→  checkedIds: Set<string>;
362→  onSelect: (id: string) => void;
363→  onToggle: (id: string) => void;
364→  showProject: boolean;
