 57→    fetchWithToken(
 58→      `/api/upload/commands?agent_type=${agentType}&os_platform=${osPlatform}`
 59→    )
 60→      .then((res) => {
 61→        if (!res.ok) throw new Error(`HTTP ${res.status}`);
 62→        return res.json();
 63→      })
 64→      .then((data: UploadCommands) => setCommands(data))
 65→      .catch(() =>
 66→        setCommands({ command: "# Failed to load command", description: "" })
 67→      )
 68→      .finally(() => setCommandLoading(false));
