385→function SelectorRow({
386→  label,
387→  options,
388→  selected,
389→  onSelect,
390→}: {
391→  label: string;
392→  options: { value: string; label: string }[];
393→  selected: string;
394→  onSelect: (value: string) => void;
395→}) {
