418→function ResultStats({ result }: { result: UploadResult }) {
419→  const hasErrors = result.errors.length > 0;
420→
421→  return (
422→    <div className="space-y-2">
423→      <div className="grid grid-cols-3 gap-2 text-xs">
424→        <StatBox label="Sessions" value={result.sessions_parsed} />
425→        <StatBox label="Steps" value={result.steps_stored} />
