432→            <p key={i} className="text-rose-400">
433→              {e.filename ? `${e.filename}: ` : ""}
434→              {e.error}
435→            </p>
436→          ))}
437→        </div>
438→      )}
439→    </div>
440→  );
441→}
442→
443→function StatBox({ label, value }: { label: string; value: number }) {
444→  return (
445→    <div className="bg-zinc-800/50 rounded px-2.5 py-1.5">
446→      <p className="text-[10px] text-zinc-500">{label}</p>
447→      <p className="text-zinc-200 font-mono text-sm">{value}</p>
448→    </div>
449→  );
450→}
